#!/usr/bin/env bash
# tilt-routine.sh — 心态 / tilt 管理 routine（赛前-赛中-赛后三段） SOP walkthrough for 德州扑克策略.
# Auto-generated by cli_writer.py. Source: research/03-workflows.md.
set -euo pipefail
SCRIPT_DIR="$(cd "$(dirname "${BASH_SOURCE[0]}")" && pwd)"
source "${SCRIPT_DIR}/../lib/common.sh"

INDUSTRY="德州扑克策略"
WORKFLOW="心态 / tilt 管理 routine（赛前-赛中-赛后三段）"

usage() {
  cat <<EOF
tilt-routine.sh — Walk through "${WORKFLOW}" SOP for ${INDUSTRY}

逐步走完这个工作流的入门 SOP, 然后做失败模式自检, 输出走查报告。

USAGE:
  ./tilt-routine.sh             # interactive
  ./tilt-routine.sh --dry-run
  ./tilt-routine.sh --json
  ./tilt-routine.sh --explain
  ./tilt-routine.sh --help
EOF
}

explain() {
  cat <<'EOT'
这个 SOP 走查脚本帮你完成 "心态 / tilt 管理 routine（赛前-赛中-赛后三段）" 工作流。

一句话: 从「让情绪/疲劳污染决策」到「一套赛前-赛中-赛后的固定 routine,把更多 session 打在 A-game、把 tilt 在升温阶段拦下」。 (evidence: [T03-S020, T03-S019])

入门 SOP 共 4 步, 失败模式自检 3 项。

相关心智模型:
  • GTO 基线 ⇄ 剥削偏离(equilibrium baseline ⇄ exploitative deviation): 先建一条**不可剥削的均衡基线 (GTO)**,再针对具体对手/人群的可观察漏洞**偏离 (exploit)** 去最大化 EV;GTO 是回得去的**锚点**,不是终点。
  • Range-first(先想范围,再想这手牌): 扑克决策的**原子单位是范围(对手在某节点所有可能持牌的概率分布)**,不是单张牌;高手把对手 put on a *range* 再随每条街的行动收窄。

来源: research/03-workflows.md.
EOT
}

DRY_RUN=0; JSON=0
for arg in "$@"; do
  case "$arg" in
    --help|-h) usage; exit 0 ;;
    --explain) explain; exit 0 ;;
    --dry-run) DRY_RUN=1 ;;
    --json) JSON=1 ;;
  esac
done

declare -a SOP_STEPS=(
  "**赛前 warm-up**:开打前过当日重点(要执行的 heuristic)+ 确认状态(精力/情绪)达标才坐下。 (evidence: [T03-S020])"
  "**赛中 tilt 监控 + injecting logic**:察觉情绪升温(身体信号 / 想报复下注)时,在**还没越过临界点前**注入逻辑(深呼吸 + 复述 +EV 原则),拦下 tilt。 (evidence: [T03-S019, T03-S021])"
  "**赛中 stop-loss / quitting**:触及预设止损(输 N buy-in / 连续 tilt)或状态崩了就**离场**,不追。 (evidence: [T03-S023, T03-S020])"
  "**赛后 cool-down / 卸载**:复盘情绪触发点(不是牌技),把负面情绪卸载,避免带进下一 session / 生活。 (evidence: [T03-S019, T03-S020])"
)
declare -a FAILURE_MODES=(
  "**没止损 + tilt 叠下风**:不设离场线,bad beat 后追损 → 单 session 抹掉长期利润。**避免**:开打前设硬止损(输 N buy-in / 连续 tilt 即走),触线无条件离场。 (evidence: [T03-S023])"
  "**越过临界点才救火**:等到已经上头才想冷静 → 拦不住。**避免**:在情绪升温的**早期信号**就注入逻辑,而非等爆发。 (evidence: [T03-S019])"
  "**只练 A-game 不管 C-game**:只想把最好状态变更好,忽视最差状态的下限 → winrate 被 C-game session 拖垮。**避免**:用 inchworm 同时管下限(减少 C-game 出现 + 让 C-game 没那么烂)。 (evidence: [T03-S019])"
)
declare -a STEP_STATUS=()
declare -a STEP_NOTES=()
declare -a FAIL_CHECK=()

ms_section "${INDUSTRY} · ${WORKFLOW} 走查"
ms_info "逐步走完 ${#SOP_STEPS[@]} 步入门 SOP。每步可标 done / skipped / blocked。"
echo

for i in "${!SOP_STEPS[@]}"; do
  ms_section "Step $((i+1))/${#SOP_STEPS[@]}: ${SOP_STEPS[$i]}"
  ms_prompt "状态? [d=done / s=skipped / b=blocked]"
  read -r status
  STEP_STATUS+=("${status:-d}")
  case "${status:-d}" in
    s) ms_prompt "跳过原因 (一句话):"; read -r note ;;
    b) ms_prompt "blocker (一句话):"; read -r note ;;
    *) note="" ;;
  esac
  STEP_NOTES+=("$note")
done

if [[ ${#FAILURE_MODES[@]} -gt 0 ]]; then
  ms_section "失败模式自检"
  for fm in "${FAILURE_MODES[@]}"; do
    if ms_confirm "你是否避免了 — '$fm' ?"; then
      FAIL_CHECK+=("✓ $fm")
    else
      FAIL_CHECK+=("✗ $fm")
    fi
  done
fi

ms_buffer_append "# ${INDUSTRY} — ${WORKFLOW} 走查报告"
ms_buffer_append ""
ms_buffer_append "_生成时间: $(date '+%Y-%m-%d %H:%M:%S')_"
ms_buffer_append ""
ms_buffer_append "## SOP 步骤"
ms_buffer_append ""
for i in "${!SOP_STEPS[@]}"; do
  status_icon="?"
  case "${STEP_STATUS[$i]}" in
    d|D) status_icon="✓" ;;
    s|S) status_icon="↷" ;;
    b|B) status_icon="✗" ;;
  esac
  if [[ -n "${STEP_NOTES[$i]}" ]]; then
    ms_buffer_append "$((i+1)). [${status_icon}] ${SOP_STEPS[$i]} — ${STEP_NOTES[$i]}"
  else
    ms_buffer_append "$((i+1)). [${status_icon}] ${SOP_STEPS[$i]}"
  fi
done
ms_buffer_append ""
if [[ ${#FAIL_CHECK[@]} -gt 0 ]]; then
  ms_buffer_append "## 失败模式自检"
  ms_buffer_append ""
  for line in "${FAIL_CHECK[@]}"; do
    ms_buffer_append "- $line"
  done
  ms_buffer_append ""
fi

if [[ $JSON -eq 1 ]]; then
  ms_emit_json \
    "workflow" "${WORKFLOW}" \
    "step_count" "${#SOP_STEPS[@]}" \
    "failure_check_count" "${#FAILURE_MODES[@]}"
elif [[ $DRY_RUN -eq 1 ]]; then
  ms_emit_md_stdout
else
  ms_emit_md_file "tilt-routine-walkthrough"
fi
